import{_ as o,o as i,c as t,a5 as e}from"./chunks/framework.B5tqjWbr.js";const g=JSON.parse('{"title":"学习记录 #0002：电力电子基础——开关器件与基本拓扑","description":"","frontmatter":{"date":"2026-06-14T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"学习记录 #0002：电力电子基础——开关器件与基本拓扑","tags":["power-electronics"],"status":"learning","summary":"**日期**：2026-06-13 **课程**：第2课 — 电力电子基础——开关器件与基本拓扑 **状态**：进行中"},"headers":[],"relativePath":"content/power/archive/old-learning-records/0002-switching-devices-and-basic-topologies.md","filePath":"content/power/archive/old-learning-records/0002-switching-devices-and-basic-topologies.md","lastUpdated":null}'),l={name:"content/power/archive/old-learning-records/0002-switching-devices-and-basic-topologies.md"};function r(s,a,n,c,d,_){return i(),t("div",null,[...a[0]||(a[0]=[e('<h1 id="学习记录-0002-电力电子基础——开关器件与基本拓扑" tabindex="-1">学习记录 #0002：电力电子基础——开关器件与基本拓扑 <a class="header-anchor" href="#学习记录-0002-电力电子基础——开关器件与基本拓扑" aria-label="Permalink to &quot;学习记录 #0002：电力电子基础——开关器件与基本拓扑&quot;">​</a></h1><p><strong>日期</strong>：2026-06-13 <strong>课程</strong>：第2课 — 电力电子基础——开关器件与基本拓扑 <strong>状态</strong>：进行中</p><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><ol><li><strong>MOSFET vs IGBT选型核心</strong>：不是简单的&quot;高压=IGBT&quot;，而是看损耗计算。MOSFET导通损耗∝I²（电阻性），IGBT导通损耗∝I（压降性）；MOSFET开关快但高压Rds(on)大，IGBT开关慢但高压导通优</li><li><strong>SiC MOSFET正在改变游戏规则</strong>：兼具MOSFET的开关速度和IGBT的高压能力，但体二极管压降高（~3V），死区续流损耗大</li><li><strong>PFC用Boost的根本原因</strong>：输入电流连续（电感电流），容易控制成正弦形；输出电压高于输入峰值</li><li><strong>死区时间双刃剑</strong>：太短→直通烧管，太长→THD增大+效率降低。SiC死区150-500ns，IGBT死区1-3μs</li><li><strong>自举预充电</strong>：逆变器启动必须先给自举电容充电（低侧脉冲），否则高侧驱动器无电源</li></ol><h2 id="损耗计算公式" tabindex="-1">损耗计算公式 <a class="header-anchor" href="#损耗计算公式" aria-label="Permalink to &quot;损耗计算公式&quot;">​</a></h2><ul><li>MOSFET导通损耗：P_cond = I_D,rms² × R_DS(on)</li><li>IGBT导通损耗：P_cond = I_C,avg × V_CE(sat)</li><li>开关损耗：P_sw = (E_on + E_off) × f_sw</li><li>驱动损耗：P_gate = Q_g × V_gs × f_sw</li></ul><h2 id="拓扑电压增益" tabindex="-1">拓扑电压增益 <a class="header-anchor" href="#拓扑电压增益" aria-label="Permalink to &quot;拓扑电压增益&quot;">​</a></h2><ul><li>Buck：V_out = D × V_in</li><li>Boost：V_out = V_in / (1-D)</li><li>Buck-Boost：V_out = -D/(1-D) × V_in</li></ul><h2 id="待深入问题" tabindex="-1">待深入问题 <a class="header-anchor" href="#待深入问题" aria-label="Permalink to &quot;待深入问题&quot;">​</a></h2><ul><li>[ ] SiC体二极管的高压降在死区期间具体怎么影响损耗？</li><li>[ ] 死区补偿的C代码怎么写？</li><li>[ ] 自举电容容量怎么精确计算？</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>进入第3课：PWM调制技术——从SPWM到SVPWM</p>',12)])])}const u=o(l,[["render",r]]);export{g as __pageData,u as default};
